BEGIN
  PROCEDURE CheckDatabaseHealth(db_name)
  BEGIN
    SHOW TABLES FROM db_name;

    FOR EACH table IN tables
    BEGIN
      CHECK TABLE table;
      IF table_status = 'OK'
        THEN ANALYZE TABLE table;
      ELSE
        REPAIR TABLE table;
      END IF
    END FOR

    OPTIMIZE TABLE tables;
  END PROCEDURE

  SHOW STATUS LIKE 'Questions';
  SHOW STATUS LIKE 'Connections';
  SHOW PROCESSLIST;
END

BEGIN
  INPUT username, hostname

  # Step 1: View current privileges
  SHOW GRANTS FOR username@hostname;

  # Step 2: Revoke all privileges
  REVOKE ALL PRIVILEGES, GRANT OPTION FROM username@hostname;

  # Step 3: Apply changes
  FLUSH PRIVILEGES;

  # Step 4: Drop the user account
  DROP USER username@hostname;

  # Step 5: Verify removal
  SELECT User, Host FROM mysql.user 
  WHERE User = username AND Host = hostname;
END
